package cmd

import (
	"context"
	"strings"
	"sync/atomic"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
)

// These tests exercise the cost-cap and infrastructure-failure wiring used
// by runAgentExecuteLoop's executor closure. The closure itself is built
// inline (so it cannot be unit-tested directly), but we exercise the same
// composition pattern here against a fake inner attempt to assert:
//
//  1. When accumulated cost exceeds the cap, the next executor invocation
//     returns the cap-tripped error WITHOUT invoking the inner attempt.
//  2. Infrastructure failures do not escalate to a smart tier — the tier
//     loop short-circuits with a deferred RetryAfter.
//
// The patterns mirror the closures in cli/cmd/agent_cmd.go (ddx-785d02f7).

// fakeAttempt records calls and returns a configured sequence of reports.
type fakeAttempt struct {
	calls   atomic.Int32
	reports []agent.ExecuteBeadReport
}

func (f *fakeAttempt) next(_ string) agent.ExecuteBeadReport {
	idx := f.calls.Add(1) - 1
	if int(idx) >= len(f.reports) {
		return f.reports[len(f.reports)-1]
	}
	return f.reports[idx]
}

// buildCostCappedExecutor mirrors the outer-executor wrapping done in
// runAgentExecuteLoop: cap check at the top, inner attempt, accumulate,
// cap check on the way out. Used by the tests below.
func buildCostCappedExecutor(tracker *escalation.CostCapTracker, inner func(beadID string) agent.ExecuteBeadReport) agent.ExecuteBeadExecutorFunc {
	return func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		if detail, capped := tracker.Tripped(); capped {
			return agent.ExecuteBeadReport{
				BeadID: beadID,
				Status: agent.ExecuteBeadStatusExecutionFailed,
				Detail: detail,
			}, nil
		}
		report := inner(beadID)
		tracker.Add(report.Harness, report.CostUSD)
		if detail, capped := tracker.Tripped(); capped {
			return agent.ExecuteBeadReport{
				BeadID: beadID,
				Status: agent.ExecuteBeadStatusExecutionFailed,
				Detail: detail,
			}, nil
		}
		return report, nil
	}
}

// TestExecuteLoopCostCap_ShortCircuitsAfterCap asserts the cost cap halts
// the queue: once accumulated billed cost reaches the cap, the next
// executor call returns the cap-tripped status without invoking the
// inner attempt.
func TestExecuteLoopCostCap_ShortCircuitsAfterCap(t *testing.T) {
	tracker := escalation.NewCostCapTracker(10.0, func(string) bool { return true })

	fake := &fakeAttempt{
		reports: []agent.ExecuteBeadReport{
			{BeadID: "ddx-1", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 6.0},
			{BeadID: "ddx-2", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 6.0},
			// Should never be reached.
			{BeadID: "ddx-3", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 1.0},
		},
	}
	exec := buildCostCappedExecutor(tracker, fake.next)

	// First call: $6 < $10 cap — succeeds and accumulates.
	r1, err := exec(context.Background(), "ddx-1")
	if err != nil {
		t.Fatalf("call 1 err = %v", err)
	}
	if r1.Status != agent.ExecuteBeadStatusSuccess {
		t.Fatalf("call 1 status = %s, want success", r1.Status)
	}

	// Second call: accumulates to $12 >= $10 cap. Returns success but
	// cap is now tripped — but wait, the post-attempt cap check fires,
	// returning the cap-tripped report instead of the success report.
	r2, err := exec(context.Background(), "ddx-2")
	if err != nil {
		t.Fatalf("call 2 err = %v", err)
	}
	if r2.Status != agent.ExecuteBeadStatusExecutionFailed {
		t.Fatalf("call 2 should have tripped post-attempt cap; status = %s", r2.Status)
	}
	if !strings.Contains(r2.Detail, "cost cap reached") {
		t.Fatalf("call 2 detail missing cost-cap message: %q", r2.Detail)
	}

	callsBefore := fake.calls.Load()

	// Third call: cap-on-entry check trips IMMEDIATELY, inner attempt
	// is NOT invoked.
	r3, err := exec(context.Background(), "ddx-3")
	if err != nil {
		t.Fatalf("call 3 err = %v", err)
	}
	if r3.Status != agent.ExecuteBeadStatusExecutionFailed {
		t.Fatalf("call 3 should be cap-tripped; status = %s", r3.Status)
	}
	if r3.BeadID != "ddx-3" {
		t.Fatalf("call 3 beadID = %s, want ddx-3", r3.BeadID)
	}
	if got := fake.calls.Load(); got != callsBefore {
		t.Fatalf("cap-on-entry must NOT invoke inner attempt; calls went %d -> %d", callsBefore, got)
	}
}

// TestExecuteLoopCostCap_LocalProvidersDoNotCount asserts that local
// and subscription providers' CostUSD never accumulates against the
// cap, even if they report a non-zero cost field.
func TestExecuteLoopCostCap_LocalProvidersDoNotCount(t *testing.T) {
	// Lookup says only "openrouter" counts.
	tracker := escalation.NewCostCapTracker(10.0, func(name string) bool {
		return name == "openrouter"
	})

	fake := &fakeAttempt{
		reports: []agent.ExecuteBeadReport{
			{BeadID: "ddx-a", Harness: "claude", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 100.0},
			{BeadID: "ddx-b", Harness: "qwen-local", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 100.0},
			{BeadID: "ddx-c", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 1.0},
		},
	}
	exec := buildCostCappedExecutor(tracker, fake.next)

	for _, id := range []string{"ddx-a", "ddx-b", "ddx-c"} {
		r, err := exec(context.Background(), id)
		if err != nil {
			t.Fatalf("call %s err = %v", id, err)
		}
		if r.Status != agent.ExecuteBeadStatusSuccess {
			t.Fatalf("call %s status = %s, want success (local/sub providers must not trip the cap)", id, r.Status)
		}
	}
	if got := tracker.Spent(); got != 1.0 {
		t.Fatalf("Spent = %.2f, want 1.0 — only openrouter should contribute", got)
	}
}

// TestInfrastructureFailureDoesNotEscalate asserts that the
// infrastructure-failure check used by the tier-escalation loop in
// runAgentExecuteLoop short-circuits without consuming escalation
// budget. We verify the contract that:
//   - IsInfrastructureFailure(execution_failed, "502 Bad Gateway") is true,
//     so the loop body's infrastructure branch fires (deferred + RetryAfter).
//   - IsInfrastructureFailure(execution_failed, "TestFoo failed") is false,
//     so the loop falls through to mark the harness unhealthy and try the
//     next tier.
//
// This is a contract test — the actual tier-escalation closure is built
// inline in runAgentExecuteLoop. The two-arm decision in that closure
// (defer-vs-escalate) is driven entirely by IsInfrastructureFailure.
func TestInfrastructureFailureDoesNotEscalate(t *testing.T) {
	cases := []struct {
		name   string
		status string
		detail string
		// wantInfra=true means "defer with retry-after, do not escalate";
		// wantInfra=false means "escalate to next tier".
		wantInfra bool
	}{
		{"502 from provider triggers defer", agent.ExecuteBeadStatusExecutionFailed, "POST /v1/chat: 502 Bad Gateway", true},
		{"connection refused triggers defer", agent.ExecuteBeadStatusExecutionFailed, "dial tcp: connection refused", true},
		{"401 unauthorized triggers defer", agent.ExecuteBeadStatusExecutionFailed, "401 Unauthorized", true},
		{"plain test failure does NOT defer (escalates)", agent.ExecuteBeadStatusExecutionFailed, "TestFoo: assertion failed", false},
		{"structural failure escalates but is not infrastructure", "structural_validation_failed", "anything 502", false},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			got := escalation.IsInfrastructureFailure(tc.status, tc.detail)
			if got != tc.wantInfra {
				t.Fatalf("IsInfrastructureFailure(%q, %q) = %v, want %v", tc.status, tc.detail, got, tc.wantInfra)
			}
			// Sanity: an infra failure on an escalatable status should
			// also have ShouldEscalate=true (so the loop body must
			// explicitly check infra BEFORE escalating).
			if tc.wantInfra && !escalation.ShouldEscalate(tc.status) {
				t.Fatalf("infrastructure-failure case %q has !ShouldEscalate; loop ordering invariant broken", tc.name)
			}
		})
	}
}

})
probeCtx, probeCancel := context.WithCancel(context.Background())
probe.Start(probeCtx)
defer func() {
	probeCancel()
	probe.Stop()
}()
if loopSink != nil {
	loopSink = workerprobe.TeeJSONL(loopSink, probe)
} else {
	loopSink = workerprobe.TeeJSONL(io.Discard, probe)
}

// Start session log tailer so the user sees progress during agent execution.
// JSON mode must stay machine-readable, so suppress the live human tailer.
tailCtx, tailCancel := context.WithCancel(context.Background())
if !asJSON {
	go agent.TailSessionLogs(tailCtx, projectRoot, cmd.OutOrStdout())
}

// Instantiate a process-local LandCoordinator for the inline land path.
// Stopped on function exit.
localCoord := serverpkg.NewLocalLandCoordinator(projectRoot, agent.RealLandingGitOps{})
defer localCoord.Stop()

// Build post-merge reviewer unless --no-review is set.
// Reviewer is on-by-default: runs at smart tier after every successful merge.
var reviewer agent.BeadReviewer
if !noReview {
	reviewer = &agent.DefaultBeadReviewer{
		ProjectRoot: projectRoot,
		BeadStore:   bead.NewStore(filepath.Join(projectRoot, ".ddx")),
		BeadEvents:  bead.NewStore(filepath.Join(projectRoot, ".ddx")),
		Harness:     reviewHarness,
		Model:       reviewModel,
	}
}

profile = agent.NormalizeRoutingProfile(profile)

// SD-024 Stage 1: dispatch flows through LoadAndResolve + RunWithConfig
// so .ddx/config.yaml's durable knobs (review_max_retries,
// no_progress_cooldown, max_no_changes_before_close, heartbeat_interval,
// agent.harness/model/permissions, etc.) reach the running loop without
// per-knob CLI plumbing. CLI flag values feed CLIOverrides which win
// over the on-disk config when set.
overrides := config.CLIOverrides{
	Assignee: resolveClaimAssignee(),
	Harness:  harness,
	Model:    model,
	Provider: provider,
	ModelRef: modelRef,
	Profile:  profile,
	Effort:   effort,
	MinPower: minPower,
}
rcfg, err := config.LoadAndResolve(projectRoot, overrides)
if err != nil {
	// Surface the LoadAndResolve error rather than letting a
	// zero-value ResolvedConfig flow into RunWithConfig — the
	// SD-024 sealed-construction sentinel would otherwise panic
	// at first accessor read instead of producing a clean CLI error.
	tailCancel()
	return fmt.Errorf("load resolved config: %w", err)
}

// Cost-cap state shared across attempts for this loop run.
// paths. Accumulated billed spend (excluding local and subscription
// providers) above --max-cost trips the cap and halts further bead
// claiming. See escalation.DefaultMaxCostUSD / CountsTowardCostCap.
costCap := escalation.NewCostCapTracker(maxCostUSD, func(harnessName string) bool {
	// Resolve the harness's billing class via the service. Treat any
	// resolution error as "count by default" (safe — we'd rather cap
	// early than silently overshoot).
	svc, svcErr := agent.NewServiceFromWorkDir(f.WorkingDir)
	if svcErr != nil {
		return true
	}
	infos, err := svc.ListHarnesses(context.Background())
	if err != nil {
		return true
	}
	for _, h := range infos {
		if h.Name == harnessName {
			return escalation.CountsTowardCostCap(h.IsLocal, h.IsSubscription, h.CostClass)
		}
	}
	return true
})
accumulateBilledCost := func(report agent.ExecuteBeadReport) {
	costCap.Add(report.Harness, report.CostUSD)
}
costCapTripped := func() (agent.ExecuteBeadReport, bool) {
	if _, tripped := costCap.Tripped(); !tripped {
		return agent.ExecuteBeadReport{}, false
	}
	spent := costCap.Spent()
	return agent.ExecuteBeadReport{
		Status: agent.ExecuteBeadStatusExecutionFailed,
		Detail: fmt.Sprintf("cost cap reached: $%.2f billed >= $%.2f cap; raise the cap or set 0 to disable. Subscription and local providers do not count.", spent, maxCostUSD),
	}, true
}

// singleTierAttempt runs one execution attempt with an explicit harness
// and model. The caller controls MinPower per rung; this helper keeps the
// profile stable and only advances the power floor.
singleTierAttempt := func(ctx context.Context, beadID string, requestedMinPower int, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
	gitOps := &agent.RealGitOps{}
	attemptProvider := provider
	if resolvedProvider != "" {
		attemptProvider = resolvedProvider
	}
	loopOverrides := config.CLIOverrides{
		Harness:           resolvedHarness,
		Model:             resolvedModel,
		Provider:          attemptProvider,
		ModelRef:          modelRef,
		Profile:           profile,
		Effort:            effort,
		MinPower:          requestedMinPower,
		MaxPower:          maxPower,
		OpaquePassthrough: treatPassthroughAsOpaque,
	}
	if requestTimeout > 0 {
		loopOverrides.ProviderRequestTimeout = &requestTimeout
	}
	attemptRcfg, _ := config.LoadAndResolve(projectRoot, loopOverrides)
	res, execErr := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, agent.ExecuteBeadRuntime{
		FromRev:     fromRev,
		BeadEvents:  bead.NewStore(filepath.Join(projectRoot, ".ddx")),
		AgentRunner: f.AgentRunnerOverride,
	}, gitOps)
	if execErr != nil && res == nil {
		return agent.ExecuteBeadReport{}, execErr
	}
	if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 {
		targetBead, _ := store.Get(beadID)
		landRes, _, landErr := agent.SubmitWithPreMergeChecks(
			ctx, projectRoot, targetBead, res,
			func(req agent.LandRequest) (*agent.LandResult, error) { return localCoord.Submit(req) },
			bead.NewStore(filepath.Join(projectRoot, ".ddx")),
			resolveClaimAssignee(), "ddx agent execute-loop",
			nil,
		)
		if landErr == nil {
			agent.ApplyLandResultToExecuteBeadResult(res, landRes)
		} else if execErr == nil {
			execErr = landErr
		}
	} else if res != nil && res.ResultRev == res.BaseRev {
		res.Outcome = "no-changes"
		res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
	} else if res != nil && res.ExitCode != 0 {
		res.Outcome = "preserved"
		res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
	}
	if execErr != nil {
		return agent.ExecuteBeadReport{}, execErr
	}
	return agent.ExecuteBeadReport{
		BeadID:                      res.BeadID,
		AttemptID:                   res.AttemptID,
		WorkerID:                    res.WorkerID,
		Harness:                     res.Harness,
		Provider:                    res.Provider,
		Model:                       res.Model,
		ActualPower:                 res.ActualPower,
		PredictedPower:              res.PredictedPower,
		PredictedSpeedTPS:           res.PredictedSpeedTPS,
		PredictedCostUSDPer1kTokens: res.PredictedCostUSDPer1kTokens,
		PredictedCostSource:         res.PredictedCostSource,
		Status:                      res.Status,
		Detail:                      res.Detail,
		SessionID:                   res.SessionID,
		BaseRev:                     res.BaseRev,
		ResultRev:                   res.ResultRev,
		PreserveRef:                 res.PreserveRef,
		NoChangesRationale:          res.NoChangesRationale,
		CostUSD:                     res.CostUSD,
		DurationMS:                  int64(res.DurationMS),
	}, nil
}

var ladderOnce sync.Once
var ladder escalationFloorFinder
loadLadder := func() escalationFloorFinder {
	ladderOnce.Do(func() {
		ladder = tierescalation.NewLadder(nil)
		svc, svcErr := agent.NewServiceFromWorkDir(projectRoot)
		if svcErr != nil {
			return
		}
		modelFilter := agentlib.ModelFilter{}
		if harness != "" {
			modelFilter.Harness = harness
		}
		modelCtx, cancel := context.WithTimeout(cmd.Context(), 2*time.Second)
		defer cancel()
		models, listErr := svc.ListModels(modelCtx, modelFilter)
		if listErr != nil {
			return
		}
		ladder = tierescalation.NewLadder(models)
	})
	return ladder
}

worker := &agent.ExecuteBeadWorker{
	Store:    store,
	Reviewer: reviewer,
	Executor: agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		// Stop AT THE START of each new bead claim if the cost cap has
		// already tripped — otherwise we'd burn one extra attempt before
		// halting the queue.
		if cappedReport, capped := costCapTripped(); capped {
			cappedReport.BeadID = beadID
			return cappedReport, nil
		}
		report, err := runEscalatingSingleTierAttempts(
			ctx,
			rcfg.MinPower(),
			loadLadder(),
			func(ctx context.Context, requestedMinPower int) (agent.ExecuteBeadReport, error) {
				return singleTierAttempt(ctx, beadID, requestedMinPower, harness, provider, model)
			},
			nil,
		)
		if err == nil {
			accumulateBilledCost(report)
			if cappedReport, capped := costCapTripped(); capped {
				cappedReport.BeadID = beadID
				return cappedReport, nil
			}
		}
		return report, err
	}),

package agent

import "strings"

// OperatorCancelReason marks a landing preserved because the operator
// cancelled the attempt mid-flight via /api/beads/<id>/cancel. ADR-022
// §Cancel SLA: the worker aborts at the next safe point (between LLM turns /
// git ops) and emits a preserved_for_review result with this exact reason.
const OperatorCancelReason = "operator_cancel"

// PushFailedReasonPrefix is the canonical Reason prefix written by the
// landing layer when `git push` rejects the new tip after a local merge or
// fast-forward succeeded. ClassifyExecuteBeadStatus matches on this prefix
// to map a merged-locally-but-not-pushed outcome to push_failed instead of
// success, so the bead stays open.
const PushFailedReasonPrefix = "landed locally; push failed:"

// PushConflictReasonPrefix marks a more specific failure mode than
// PushFailedReasonPrefix: the local push was rejected because the remote
// advanced, the loop attempted an automatic pull/merge to recover, and the
// merge produced a conflict the loop cannot resolve. The bead is parked for
// human review with a short cooldown rather than a year-long park.
const PushConflictReasonPrefix = "landed locally; push conflict:"

// FailureMode constants classify *why* an execution did not land cleanly.
// They are orthogonal to Outcome/Status: a single failed attempt carries one
// outcome (e.g. preserved) and one failure mode (e.g. merge_conflict) so
// measurement surfaces can aggregate failures by cause.
const (
	FailureModeContextOverflow                = "context_overflow"
	FailureModeMergeConflict                  = "merge_conflict"
	FailureModeTestFailure                    = "test_failure"
	FailureModeBuildFailure                   = "build_failure"
	FailureModeTimeout                        = "timeout"
	FailureModeAuthError                      = "auth_error"
	FailureModeNoChanges                      = "no_changes"
	FailureModeNoEvidenceProduced             = "no_evidence_produced"
	FailureModeRatchetMiss                    = "ratchet_miss"
	FailureModeNoViableProvider               = "no_viable_provider"
	FailureModeHarnessNotInstalled            = "harness_not_installed"
	FailureModeBlockedByPassthroughConstraint = "blocked_by_passthrough_constraint"
	FailureModeAgentPowerUnsatisfied          = "agent_power_unsatisfied"
	FailureModeLockContention                 = "lock_contention"
	FailureModeUnknown                        = "unknown"
)

// ClassifyFailureMode derives a failure_mode for a worker-level result from
// its outcome, exit code, and error message. Returns "" when the outcome is
// task_succeeded (success carries no failure mode). task_no_changes always
// maps to FailureModeNoChanges regardless of error text.
//
// For task_failed (or non-zero exit code), the error message is scanned for
// well-known substrings. The order matters: context/auth/timeout patterns
// are checked before generic test/build patterns so a "test timed out"
// classifies as timeout rather than test_failure. Anything unrecognised
// maps to FailureModeUnknown so aggregates never hide a missed pattern.
func ClassifyFailureMode(outcome string, exitCode int, errMsg string) string {
	switch outcome {
	case ExecuteBeadOutcomeTaskSucceeded:
		if exitCode == 0 {
			return ""
		}
		// Degenerate: success outcome with non-zero exit. Treat as unknown
		// failure rather than success so the aggregate flags the anomaly.
	case ExecuteBeadOutcomeTaskNoChanges:
		return FailureModeNoChanges
	case ExecuteBeadOutcomeTaskNoEvidence:
		return FailureModeNoEvidenceProduced
	}

	lower := strings.ToLower(errMsg)
	switch {
	case IsLockContentionError(errMsg):
		return FailureModeLockContention
	case containsAny(lower,
		"passthrough constraint unsatisfiable",
		"passthrough constraint:",
		"max_power is less than min_power",
		"max_power exceeds min_power",
		"harness cannot satisfy power constraint",
		"harness pin incompatible with power bounds",
		"model pin incompatible with power bounds",
		"provider pin incompatible with power bounds"):
		return FailureModeBlockedByPassthroughConstraint
	case containsAny(lower,
		"agent power unsatisfied",
		"no model meets min_power",
		"no model with power >=",
		"minimum power not achievable",
		"min_power constraint cannot be satisfied"):
		return FailureModeAgentPowerUnsatisfied
	case containsAny(lower,
		"executable file not found in $path",
		"executable file not found",
		"no such file or directory") &&
		containsAny(lower, "exec:", "harness", "claude", "agent", "codex", "gemini"):
		return FailureModeHarnessNotInstalled
	case containsAny(lower,
		"no viable harness",
		"no harness configured",
		"failed to initialize routing service",
		"no viable provider"):
		return FailureModeNoViableProvider
	case containsAny(lower,
		"context length",
		"context_length_exceeded",
		"context window",
		"maximum context",
		"prompt is too long",
		"prompt too long",
		"token limit",
		"too many tokens",
		"exceeds the context"):
		return FailureModeContextOverflow
	case containsAny(lower,
		"unauthorized",
		"401 unauthorized",
		"invalid api key",
		"invalid_api_key",
		"authentication failed",
		"authentication_error",
		"no api key",
		"missing api key",
		"quota exceeded",
		"insufficient quota",
		"insufficient_quota",
		"rate limit",
		"rate_limit",
		"429"):
		return FailureModeAuthError
	case containsAny(lower,
		"timeout",
		"timed out",
		"context deadline exceeded",
		"deadline exceeded",
		"signal: killed"):
		return FailureModeTimeout
	case containsAny(lower,
		"merge conflict",
		"ff-merge not possible",
		"merge failed",
		"automatic merge failed"):
		return FailureModeMergeConflict
	case containsAny(lower,
		"build failed",
		"compilation failed",
		"compile error",
		"compilation error",
		"cannot find package",
		"undefined:",
		"undefined reference",
		"syntax error"):
		return FailureModeBuildFailure
	case containsAny(lower,
		"test failed",
		"tests failed",
		"--- fail:",
		"assertion failed",
		"test failure"):
		return FailureModeTestFailure
	}
	if exitCode != 0 {
		return FailureModeUnknown
	}
	return ""
}

// containsAny reports whether s contains any of the given substrings. s is
// assumed to already be lower-cased by the caller.
func containsAny(s string, needles ...string) bool {
	for _, n := range needles {
		if n == "" {
			continue
		}
		if strings.Contains(s, n) {
			return true
		}
	}
	return false
}

// classifyLandingFailureMode computes the final failure_mode for a result
// after the orchestrator has made its landing decision. It prefers
// landing-specific signals (merge conflict, gate failure) over the worker's
// classification and falls back to workerMode for worker-level failures
// (agent execution failed, context overflow, etc.). Returns "" when the
// bead merged cleanly.
func classifyLandingFailureMode(landingOutcome, landingReason string, gateResults []GateCheckResult, workerMode string) string {
	switch landingOutcome {
	case "merged":
		return ""
	case "no-changes", ExecuteBeadOutcomeTaskNoChanges:
		return FailureModeNoChanges
	case "no-evidence", ExecuteBeadOutcomeTaskNoEvidence:
		return FailureModeNoEvidenceProduced
	case "error":
		if workerMode != "" {
			return workerMode
		}
		return FailureModeUnknown
	case "preserved":
		switch landingReason {
		case "merge conflict", "merge failed", "ff-merge not possible":
			return FailureModeMergeConflict
		case "post-run checks failed":
			return classifyGateFailure(gateResults)
		case RatchetPreserveReason:
			return FailureModeRatchetMiss
		case OperatorCancelReason:
			return ""
		}
		// Other preserved reasons (e.g. "agent execution failed",
		// "--no-merge specified") defer to the worker's classification.
		if workerMode != "" {
			return workerMode
		}
		return FailureModeUnknown
	}
	if workerMode != "" {
		return workerMode
	}
	return FailureModeUnknown
}

